import os, shutil, json, subprocess, datetime

print('=== CLEANUP STEP 3: Rustup + Desktop + SSL ===')
print()

home = os.path.expanduser('~')
desktop = os.path.join(home, 'Desktop')
log = {'rustup': {}, 'desktop': {}, 'ssl': {}}

# ===== PART 1: Remove Rustup =====
print('[1] Removing Rustup (no .rs projects found, cargo empty)...')
rustup_dir = os.path.join(home, '.rustup')
cargo_dir = os.path.join(home, '.cargo')
rust_freed = 0

if os.path.exists(rustup_dir):
    for root, dirs, files in os.walk(rustup_dir):
        for f in files:
            try:
                rust_freed += os.path.getsize(os.path.join(root, f))
            except:
                pass
    shutil.rmtree(rustup_dir, ignore_errors=True)
    if not os.path.exists(rustup_dir):
        print(f'  .rustup removed: {round(rust_freed/(1024**2), 1)} MB freed')
    else:
        print('  WARNING: .rustup partially removed')

cargo_freed = 0
if os.path.exists(cargo_dir):
    for root, dirs, files in os.walk(cargo_dir):
        for f in files:
            try:
                cargo_freed += os.path.getsize(os.path.join(root, f))
            except:
                pass
    shutil.rmtree(cargo_dir, ignore_errors=True)
    if not os.path.exists(cargo_dir):
        print(f'  .cargo removed: {round(cargo_freed/(1024**2), 1)} MB freed')
    else:
        print('  WARNING: .cargo partially removed')

log['rustup'] = {'freed_mb': round((rust_freed + cargo_freed)/(1024**2), 1), 'status': 'removed'}
print(f'  Total Rust freed: {log["rustup"]["freed_mb"]} MB')

# ===== PART 2: Organize Desktop =====
print()
print('[2] Organizing Desktop...')

# Create organization folders
folders_map = {
    'Projects': [],
    'Images': [],
    'Documents': [],
    'Tools': [],
    'Shortcuts': []
}

# Protected items - DO NOT MOVE
protected = ['antigravity', 'desktop.ini', 'Antigravity.lnk']

# Categorize items
project_folders = ['my-restaurant-app', 'clodinary', 'final agent', 'mcp project', 'MCP-SuperAssistant-0.6.0', 'Nouveau dossier (2)', 'souhila', 'test_png', 'Treiber_AB-88H_64bit']
image_files = ['.png', '.jpg', '.jpeg', '.gif', '.bmp', '.svg', '.ico']
doc_files = ['.txt', '.pdf', '.doc', '.docx', '.md', '.html', '.json', '.accdb', '.csv', '.xls', '.xlsx']
tool_files = ['.exe', '.msi', '.bat', '.cmd', '.ps1', '.py']
shortcut_files = ['.lnk', '.url']

moved = []
failed = []
skipped = []

for item in os.listdir(desktop):
    fp = os.path.join(desktop, item)

    # Skip protected items
    if item.lower() in [p.lower() for p in protected]:
        skipped.append(item)
        continue

    # Skip if already in an organization folder
    if item in folders_map:
        skipped.append(item)
        continue

    ext = os.path.splitext(item)[1].lower()
    target_folder = None

    if os.path.isdir(fp):
        if item in project_folders:
            target_folder = 'Projects'
        else:
            skipped.append(item)
            continue
    elif ext in shortcut_files and item != 'Antigravity.lnk':
        target_folder = 'Shortcuts'
    elif ext in image_files:
        target_folder = 'Images'
    elif ext in doc_files:
        target_folder = 'Documents'
    elif ext in tool_files:
        target_folder = 'Tools'
    else:
        # Unknown - put in Documents as safe default
        if os.path.isfile(fp):
            target_folder = 'Documents'

    if target_folder:
        target_dir = os.path.join(desktop, target_folder)
        os.makedirs(target_dir, exist_ok=True)
        try:
            dest = os.path.join(target_dir, item)
            if not os.path.exists(dest):
                shutil.move(fp, dest)
                moved.append(f'{item} -> {target_folder}/')
                print(f'  Moved: {item} -> {target_folder}/')
            else:
                skipped.append(f'{item} (already exists in {target_folder})')
        except Exception as e:
            failed.append(f'{item}: {str(e)}')
            print(f'  FAILED: {item} - {e}')

log['desktop'] = {'moved': moved, 'skipped': skipped, 'failed': failed}
print(f'  Moved: {len(moved)} items')
print(f'  Skipped: {len(skipped)} items (protected/already organized)')
print(f'  Failed: {len(failed)} items')

# ===== PART 3: Fix SSL / upgrade certifi =====
print()
print('[3] Upgrading certifi for SSL fix...')
try:
    result = subprocess.run(
        ['pip', 'install', '--upgrade', 'certifi'],
        capture_output=True, text=True, timeout=120
    )
    print(f'  {result.stdout.strip()}')
    if result.returncode == 0:
        log['ssl'] = {'status': 'upgraded', 'output': result.stdout.strip()}
    else:
        log['ssl'] = {'status': 'failed', 'error': result.stderr.strip()}
        print(f'  ERROR: {result.stderr.strip()}')
except Exception as e:
    log['ssl'] = {'status': 'failed', 'error': str(e)}
    print(f'  ERROR: {e}')

# ===== FINAL SUMMARY =====
print()
print('=' * 50)
print('  STEP 3 SUMMARY')
print('=' * 50)
print(f'  Rustup removed: {log["rustup"]["freed_mb"]} MB freed')
print(f'  Desktop organized: {len(moved)} items moved into folders')
print(f'  SSL certifi: {log["ssl"]["status"]}')
print()

# Save log
report_dir = os.path.join(home, 'agent_reports')
os.makedirs(report_dir, exist_ok=True)
with open(os.path.join(report_dir, 'cleanup_step3_log.json'), 'w', encoding='utf-8') as f:
    json.dump(log, f, indent=2, ensure_ascii=False, default=str)

print(f'Log saved to: {os.path.join(report_dir, "cleanup_step3_log.json")}')
print('=== STEP 3 COMPLETE ===')
